#include <stdio.h>
#include <string.h>
#define MAX 100
int main() {
    int n;
    scanf("%d", &n);
    char names[n][MAX];
    int problems[n];
    for (int i = 0; i < n; i++) {
        scanf("%s %d", names[i], &problems[i]);
    }
    int max = 0;
    for (int i = 0; i < n; i++) {
        if (problems[i] > max) {
            max = problems[i];
        }
    }
    for (int i = 0; i < n; i++) {
        if (problems[i] == max) {
            printf("%s\n", names[i]);
        }
    }
    return 0;
}

