import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        String[] names = new String[n];
        int[] problems = new int[n];
        for (int i = 0; i < n; i++) {
            names[i] = scanner.next();
            problems[i] = scanner.nextInt();
        }
        int max = 0;
        for (int i = 0; i < n; i++) {
            if (problems[i] > max) {
                max = problems[i];
            }
        }
        for (int i = 0; i < n; i++) {
            if (problems[i] == max) {
                System.out.println(names[i]);
            }
        }
    }
}

code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let names = [];
let problems = [];
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        let [name, problem] = input.split(' ');
        names.push(name);
        problems.push(parseInt(problem));
        if (names.length === n) {
            let max = Math.max(...problems);
            for (let i = 0; i < n; i++) {
                if (problems[i] === max) {
                    console.log(names[i]);
                }
            }
            rl.close();
        }
    }
});
